import { Kernel } from '@semantic-kernel/core';
import { VexValidator } from 'vex-sdk';

const kernel = new Kernel();

const legalValidator = new VexValidator({
  policyId: 'legal-compliance',
  rules: ['require_attorney_review', 'block_hallucinations']
});

// Filter planner results
kernel.addPostInvocationHook(async (context) => {
  if (context.function.name.includes('planner')) {
    const validated = await legalValidator.validate(context.result);
    if (!validated.valid) {
      throw new Error(`Compliance violation: ${validated.issues}`);
    }
    context.result = validated.output;
  }
});

// Example legal planner usage
const plan = await kernel.invoke('LegalPlanner', 'create_brief', { topic: 'privilege waiver' });
console.log(plan);
